import React from 'react';
import './Multimedia.css';
import Slideshow from './Slideshow.js';

const headline = 'Rats Orchestrate Takeover of New York City';

class Multimedia extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      min: 0,
      max: 10,
      index: 0,
    };
  }

  increase = (direction) => {
    let temp;
    if (direction == true) {
      temp = 1;
    } else {
      temp = -1;
    }
    this.setState({
      index: this.state.index + temp,
    })
  }

  render() {
    return (
      <div className='Multimedia'>
        <button onClick={() => this.increase(true)}>increase</button>
        <button onClick={() => this.increase(false)}>decrease</button>
        {this.state.index}


      </div>
    );
  }
}

export default Multimedia;
